package com.chaobo.scm.supplier.application.contract;

import com.chaobo.scm.supplier.application.shared.*;import com.chaobo.scm.supplier.domain.contract.*;import com.chaobo.scm.supplier.domain.shared.IdentifierGenerator;import com.chaobo.scm.supplier.infrastructure.persistence.contract.SupplierContractExpiryMapper;import org.springframework.scheduling.annotation.Scheduled;import org.springframework.stereotype.Component;import org.springframework.transaction.annotation.Transactional;import java.util.Set;
@Component public class SupplierContractExpiryTask {private final SupplierContractExpiryMapper candidates;private final SupplierContractRepository contracts;private final OutboxRepository outbox;private final AuditLogRepository audit;private final IdentifierGenerator ids;public SupplierContractExpiryTask(SupplierContractExpiryMapper candidates,SupplierContractRepository contracts,OutboxRepository outbox,AuditLogRepository audit,IdentifierGenerator ids){this.candidates=candidates;this.contracts=contracts;this.outbox=outbox;this.audit=audit;this.ids=ids;}@Scheduled(cron="${scm.supplier.contract-expire-cron:0 10 0 * * *}")@Transactional public void expire(){for(long id:candidates.expiredIds()){var contract=contracts.find(id).orElse(null);if(contract==null)continue;contract.expire(0,ids);var events=contract.pullEvents();if(events.isEmpty())continue;contracts.save(contract,0);outbox.saveAll(events);var context=new CommandContext(0,"SYSTEM",0,null,"contract-expire-"+id,null,"contract-expire-"+id,Set.of());audit.save(context,"EXPIRE_CONTRACT","SUPPLIER_CONTRACT",id,contract.no(),null,"{\"status\":"+contract.status().code()+"}");}}}
